def min_operations_to_form_portal(t, test_cases):
    results = []

    for case in test_cases:
        n, m, grid = case
        min_operations = float('inf')

        for i in range(n):
            for j in range(m):
                for a in range(5, n - i + 1):
                    for b in range(4, m - j + 1):
                        # Calculate the number of changes needed for this sub-rectangle
                        changes = 0

                        # Top and bottom rows
                        for y in range(b):
                            if y == 0 or y == b - 1:
                                # Corners can be any type, no change needed
                                continue
                            if grid[i][j + y] != '1':
                                changes += 1
                            if grid[i + a - 1][j + y] != '1':
                                changes += 1

                        # Left and right columns
                        for x in range(a):
                            if x == 0 or x == a - 1:
                                # Corners can be any type, no change needed
                                continue
                            if grid[i + x][j] != '1':
                                changes += 1
                            if grid[i + x][j + b - 1] != '1':
                                changes += 1

                        # Interior blocks
                        for x in range(1, a - 1):
                            for y in range(1, b - 1):
                                if grid[i + x][j + y] != '0':
                                    changes += 1

                        # Update the minimum operations needed
                        min_operations = min(min_operations, changes)

        results.append(min_operations)

    return results

