def min_operations_to_portal(t, test_cases):
    results = []

    for case in test_cases:
        n, m, grid = case
        min_operations = float('inf')

        # Iterate over all possible top-left corners of the sub-rectangle
        for top in range(n):
            for left in range(m):
                # Iterate over all possible bottom-right corners of the sub-rectangle
                for bottom in range(top + 4, n):
                    for right in range(left + 3, m):
                        # Calculate the number of operations needed to make this sub-rectangle a portal
                        operations = 0

                        # Check the top and bottom borders
                        for y in range(left + 1, right):
                            if grid[top][y] != '1':
                                operations += 1
                            if grid[bottom][y] != '1':
                                operations += 1

                        # Check the left and right borders
                        for x in range(top + 1, bottom):
                            if grid[x][left] != '1':
                                operations += 1
                            if grid[x][right] != '1':
                                operations += 1

                        # Check the inner part
                        for x in range(top + 1, bottom):
                            for y in range(left + 1, right):
                                if grid[x][y] != '0':
                                    operations += 1

                        # Update the minimum operations needed
                        min_operations = min(min_operations, operations)

        # If no valid portal was found, set min_operations to 0
        if min_operations == float('inf'):
            min_operations = 0

        results.append(min_operations)

    return results

