        half_duration = total_duration // 2

        # Initialize a set to track possible sums
        possible_sums = {0}

        # Update possible sums with one-minute songs
        for _ in range(a):
            new_sums = set()
            for s in possible_sums:
                if s + 1 <= half_duration:
                    new_sums.add(s + 1)
            possible_sums.update(new_sums)

        # Update possible sums with two-minute songs
        for _ in range(b):
            new_sums = set()
            for s in possible_sums:
                if s + 2 <= half_duration:
