            for s in possible_sums:
                if s + 3 <= half_duration:
                    new_sums.add(s + 3)
            possible_sums.update(new_sums)

        # Find the largest possible sum that is less than or equal to half of the total duration
        max_possible_sum = max(possible_sums)
        min_difference = total_duration - 2 * max_possible_sum
        results.append(min_difference)

